#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t X, Y; scanf("%" PRId64 " %" PRId64, &X, &Y);
        int64_t per = 2 * Y;
        int64_t ans = (per==0)?0: X / per;
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

